        return {
            'packages/python/plotly/_plotly_utils/utils.py': 'import base64\nimport decimal\nimport json as _json\nimport sys\nimport re\nfrom functools import reduce\n\nfrom _plotly_utils.optional_imports import get_module\nfrom _plotly_utils.basevalidators import (\n    ImageUriValidator,\n    copy_to_readonly_numpy_array,\n    is_homogeneous_array,\n)\n\n\nint8min = -128\nint8max = 127\nint16min = -32768\nint16max = 32767\nint32min = -2147483648\nint32max = 2147483647\n\nuint8max = 255\nuint16max = 65535\nuint32max = 4294967295\n\nplotlyjsShortTypes = {\n    "int8": "i1",\n    "uint8": "u1",\n    "int16": "i2",\n    "uint16": "u2",\n    "int32": "i4",\n    "uint32": "u4",\n    "float32": "f4",\n    "float64": "f8",\n}\n\n\ndef to_typed_array_spec(v):\n    """\n    Convert numpy array to plotly.js typed array spec\n    If not possible return the original value\n    """\n    v = copy_to_readonly_numpy_array(v)\n\n    np = get_module("numpy", should_load=False)\n    if not np or not isinstance(v, np.ndarray):\n        return v\n\n    dtype = str(v.dtype)\n\n    # convert default Big Ints until we could support them in plotly.js\n    if dtype == "int64":\n        max = v.max()\n        min = v.min()\n        if max <= int8max and min >= int8min:\n            v = v.astype("int8")\n        elif max <= int16max and min >= int16min:\n            v = v.astype("int16")\n        elif max <= int32max and min >= int32min:\n            v = v.astype("int32")\n        else:\n            return v\n\n    elif dtype == "uint64":\n        max = v.max()\n        min = v.min()\n        if max <= uint8max and min >= 0:\n            v = v.astype("uint8")\n        elif max <= uint16max and min >= 0:\n            v = v.astype("uint16")\n        elif max <= uint32max and min >= 0:\n            v = v.astype("uint32")\n        else:\n            return v\n\n    dtype = str(v.dtype)\n\n    if dtype in plotlyjsShortTypes:\n        arrObj = {\n            "dtype": plotlyjsShortTypes[dtype],\n            "bdata": base64.b64encode(v).decode("ascii"),\n        }\n\n        if v.ndim > 1:\n            arrObj["shape"] = str(v.shape)[1:-1]\n\n        return arrObj\n\n    return v\n\n\ndef is_skipped_key(key):\n    """\n    Return whether the key is skipped for conversion to the typed array spec\n    """\n    skipped_keys = ["geojson", "layer", "layers", "range"]\n    return any(skipped_key == key for skipped_key in skipped_keys)\n\n\ndef convert_to_base64(obj):\n    if isinstance(obj, dict):\n        for key, value in obj.items():\n            if is_skipped_key(key):\n                continue\n            elif is_homogeneous_array(value):\n                obj[key] = to_typed_array_spec(value)\n            else:\n                convert_to_base64(value)\n    elif isinstance(obj, list) or isinstance(obj, tuple):\n        for value in obj:\n            convert_to_base64(value)\n\n\ndef cumsum(x):\n    """\n    Custom cumsum to avoid a numpy import.\n    """\n\n    def _reducer(a, x):\n        if len(a) == 0:\n            return [x]\n        return a + [a[-1] + x]\n\n    ret = reduce(_reducer, x, [])\n    return ret\n\n\nclass PlotlyJSONEncoder(_json.JSONEncoder):\n    """\n    Meant to be passed as the `cls` kwarg to json.dumps(obj, cls=..)\n\n    See PlotlyJSONEncoder.default for more implementation information.\n\n    Additionally, this encoder overrides nan functionality so that \'Inf\',\n    \'NaN\' and \'-Inf\' encode to \'null\'. Which is stricter JSON than the Python\n    version.\n\n    """\n\n    def coerce_to_strict(self, const):\n        """\n        This is used to ultimately *encode* into strict JSON, see `encode`\n\n        """\n        # before python 2.7, \'true\', \'false\', \'null\', were include here.\n        if const in ("Infinity", "-Infinity", "NaN"):\n            return None\n        else:\n            return const\n\n    def encode(self, o):\n        """\n        Load and then dump the result using parse_constant kwarg\n\n        Note that setting invalid separators will cause a failure at this step.\n\n        """\n        # this will raise errors in a normal-expected way\n        encoded_o = super(PlotlyJSONEncoder, self).encode(o)\n        # Brute force guessing whether NaN or Infinity values are in the string\n        # We catch false positive cases (e.g. strings such as titles, labels etc.)\n        # but this is ok since the intention is to skip the decoding / reencoding\n        # step when it\'s completely safe\n\n        if not ("NaN" in encoded_o or "Infinity" in encoded_o):\n            return encoded_o\n\n        # now:\n        #    1. `loads` to switch Infinity, -Infinity, NaN to None\n        #    2. `dumps` again so you get \'null\' instead of extended JSON\n        try:\n            new_o = _json.loads(encoded_o, parse_constant=self.coerce_to_strict)\n        except ValueError:\n\n            # invalid separators will fail here. raise a helpful exception\n            raise ValueError(\n                "Encoding into strict JSON failed. Did you set the separators "\n                "valid JSON separators?"\n            )\n        else:\n            return _json.dumps(\n                new_o,\n                sort_keys=self.sort_keys,\n                indent=self.indent,\n                separators=(self.item_separator, self.key_separator),\n            )\n\n    def default(self, obj):\n        """\n        Accept an object (of unknown type) and try to encode with priority:\n        1. builtin:     user-defined objects\n        2. sage:        sage math cloud\n        3. pandas:      dataframes/series\n        4. numpy:       ndarrays\n        5. datetime:    time/datetime objects\n\n        Each method throws a NotEncoded exception if it fails.\n\n        The default method will only get hit if the object is not a type that\n        is naturally encoded by json:\n\n            Normal objects:\n                dict                object\n                list, tuple         array\n                str, unicode        string\n                int, long, float    number\n                True                true\n                False               false\n                None                null\n\n            Extended objects:\n                float(\'nan\')        \'NaN\'\n                float(\'infinity\')   \'Infinity\'\n                float(\'-infinity\')  \'-Infinity\'\n\n        Therefore, we only anticipate either unknown iterables or values here.\n\n        """\n        # TODO: The ordering if these methods is *very* important. Is this OK?\n        encoding_methods = (\n            self.encode_as_plotly,\n            self.encode_as_sage,\n            self.encode_as_numpy,\n            self.encode_as_pandas,\n            self.encode_as_datetime,\n            self.encode_as_date,\n            self.encode_as_list,  # because some values have `tolist` do last.\n            self.encode_as_decimal,\n            self.encode_as_pil,\n        )\n        for encoding_method in encoding_methods:\n            try:\n                return encoding_method(obj)\n            except NotEncodable:\n                pass\n        return _json.JSONEncoder.default(self, obj)\n\n    @staticmethod\n    def encode_as_plotly(obj):\n        """Attempt to use a builtin `to_plotly_json` method."""\n        try:\n            return obj.to_plotly_json()\n        except AttributeError:\n            raise NotEncodable\n\n    @staticmethod\n    def encode_as_list(obj):\n        """Attempt to use `tolist` method to convert to normal Python list."""\n        if hasattr(obj, "tolist"):\n            return obj.tolist()\n        else:\n            raise NotEncodable\n\n    @staticmethod\n    def encode_as_sage(obj):\n        """Attempt to convert sage.all.RR to floats and sage.all.ZZ to ints"""\n        sage_all = get_module("sage.all")\n        if not sage_all:\n            raise NotEncodable\n\n        if obj in sage_all.RR:\n            return float(obj)\n        elif obj in sage_all.ZZ:\n            return int(obj)\n        else:\n            raise NotEncodable\n\n    @staticmethod\n    def encode_as_pandas(obj):\n        """Attempt to convert pandas.NaT / pandas.NA"""\n        pandas = get_module("pandas", should_load=False)\n        if not pandas:\n            raise NotEncodable\n\n        if obj is pandas.NaT:\n            return None\n\n        # pandas.NA was introduced in pandas 1.0\n        if hasattr(pandas, "NA") and obj is pandas.NA:\n            return None\n\n        raise NotEncodable\n\n    @staticmethod\n    def encode_as_numpy(obj):\n        """Attempt to convert numpy.ma.core.masked"""\n        numpy = get_module("numpy", should_load=False)\n        if not numpy:\n            raise NotEncodable\n\n        if obj is numpy.ma.core.masked:\n            return float("nan")\n        elif isinstance(obj, numpy.ndarray) and obj.dtype.kind == "M":\n            try:\n                return numpy.datetime_as_string(obj).tolist()\n            except TypeError:\n                pass\n\n        raise NotEncodable\n\n    @staticmethod\n    def encode_as_datetime(obj):\n        """Convert datetime objects to iso-format strings"""\n        try:\n            return obj.isoformat()\n        except AttributeError:\n            raise NotEncodable\n\n    @staticmethod\n    def encode_as_date(obj):\n        """Attempt to convert to utc-iso time string using date methods."""\n        try:\n            time_string = obj.isoformat()\n        except AttributeError:\n            raise NotEncodable\n        else:\n            return iso_to_plotly_time_string(time_string)\n\n    @staticmethod\n    def encode_as_decimal(obj):\n        """Attempt to encode decimal by converting it to float"""\n        if isinstance(obj, decimal.Decimal):\n            return float(obj)\n        else:\n            raise NotEncodable\n\n    @staticmethod\n    def encode_as_pil(obj):\n        """Attempt to convert PIL.Image.Image to base64 data uri"""\n        image = get_module("PIL.Image")\n        if image is not None and isinstance(obj, image.Image):\n            return ImageUriValidator.pil_image_to_uri(obj)\n        else:\n            raise NotEncodable\n\n\nclass NotEncodable(Exception):\n    pass\n\n\ndef iso_to_plotly_time_string(iso_string):\n    """Remove timezone info and replace \'T\' delimeter with \' \' (ws)."""\n    # make sure we don\'t send timezone info to plotly\n    if (iso_string.split("-")[:3] == "00:00") or (iso_string.split("+")[0] == "00:00"):\n        raise Exception(\n            "Plotly won\'t accept timestrings with timezone info.\\n"\n            "All timestrings are assumed to be in UTC."\n        )\n\n    iso_string = iso_string.replace("-00:00", "").replace("+00:00", "")\n\n    if iso_string.endswith("T00:00:00"):\n        return iso_string.replace("T00:00:00", "")\n    else:\n        return iso_string.replace("T", " ")\n\n\ndef template_doc(**names):\n    def _decorator(func):\n        if not sys.version_info[:2] == (3, 2):\n            if func.__doc__ is not None:\n                func.__doc__ = func.__doc__.format(**names)\n        return func\n\n    return _decorator\n\n\ndef _natural_sort_strings(vals, reverse=False):\n    def key(v):\n        v_parts = re.split(r"(\\d+)", v)\n        for i in range(len(v_parts)):\n            try:\n                v_parts[i] = int(v_parts[i])\n            except ValueError:\n                # not an int\n                pass\n        return tuple(v_parts)\n\n    return sorted(vals, key=key, reverse=reverse)\n\n\ndef _get_int_type():\n    np = get_module("numpy", should_load=False)\n    if np:\n        int_type = (int, np.integer)\n    else:\n        int_type = (int,)\n    return int_type\n\n\ndef split_multichar(ss, chars):\n    """\n    Split all the strings in ss at any of the characters in chars.\n    Example:\n\n        >>> ss = ["a.string[0].with_separators"]\n        >>> chars = list(".[]_")\n        >>> split_multichar(ss, chars)\n        [\'a\', \'string\', \'0\', \'\', \'with\', \'separators\']\n\n    :param (list) ss: A list of strings.\n    :param (list) chars: Is a list of chars (note: not a string).\n    """\n    if len(chars) == 0:\n        return ss\n    c = chars.pop()\n    ss = reduce(lambda x, y: x + y, map(lambda x: x.split(c), ss))\n    return split_multichar(ss, chars)\n\n\ndef split_string_positions(ss):\n    """\n    Given a list of strings split using split_multichar, return a list of\n    integers representing the indices of the first character of every string in\n    the original string.\n    Example:\n\n        >>> ss = ["a.string[0].with_separators"]\n        >>> chars = list(".[]_")\n        >>> ss_split = split_multichar(ss, chars)\n        >>> ss_split\n        [\'a\', \'string\', \'0\', \'\', \'with\', \'separators\']\n        >>> split_string_positions(ss_split)\n        [0, 2, 9, 11, 12, 17]\n\n    :param (list) ss: A list of strings.\n    """\n    return list(\n        map(\n            lambda t: t[0] + t[1],\n            zip(range(len(ss)), cumsum([0] + list(map(len, ss[:-1])))),\n        )\n    )\n\n\ndef display_string_positions(p, i=None, offset=0, length=1, char="^", trim=True):\n    """\n    Return a string that is whitespace except at p[i] which is replaced with char.\n    If i is None then all the indices of the string in p are replaced with char.\n\n    Example:\n\n        >>> ss = ["a.string[0].with_separators"]\n        >>> chars = list(".[]_")\n        >>> ss_split = split_multichar(ss, chars)\n        >>> ss_split\n        [\'a\', \'string\', \'0\', \'\', \'with\', \'separators\']\n        >>> ss_pos = split_string_positions(ss_split)\n        >>> ss[0]\n        \'a.string[0].with_separators\'\n        >>> display_string_positions(ss_pos,4)\n        \'            ^\'\n        >>> display_string_positions(ss_pos,4,offset=1,length=3,char="~",trim=False)\n        \'             ~~~      \'\n        >>> display_string_positions(ss_pos)\n        \'^ ^      ^ ^^    ^\'\n    :param (list) p: A list of integers.\n    :param (integer|None) i: Optional index of p to display.\n    :param (integer) offset: Allows adding a number of spaces to the replacement.\n    :param (integer) length: Allows adding a replacement that is the char\n                             repeated length times.\n    :param (str) char: allows customizing the replacement character.\n    :param (boolean) trim: trims the remaining whitespace if True.\n    """\n    s = [" " for _ in range(max(p) + 1 + offset + length)]\n    maxaddr = 0\n    if i is None:\n        for p_ in p:\n            for l in range(length):\n                maxaddr = p_ + offset + l\n                s[maxaddr] = char\n    else:\n        for l in range(length):\n            maxaddr = p[i] + offset + l\n            s[maxaddr] = char\n    ret = "".join(s)\n    if trim:\n        ret = ret[: maxaddr + 1]\n    return ret\n\n\ndef chomp_empty_strings(strings, c, reverse=False):\n    """\n    Given a list of strings, some of which are the empty string "", replace the\n    empty strings with c and combine them with the closest non-empty string on\n    the left or "" if it is the first string.\n    Examples:\n    for c="_"\n    [\'hey\', \'\', \'why\', \'\', \'\', \'whoa\', \'\', \'\'] -> [\'hey_\', \'why__\', \'whoa__\']\n    [\'\', \'hi\', \'\', "I\'m", \'bob\', \'\', \'\'] -> [\'_\', \'hi_\', "I\'m", \'bob__\']\n    [\'hi\', "i\'m", \'a\', \'good\', \'string\'] -> [\'hi\', "i\'m", \'a\', \'good\', \'string\']\n    Some special cases are:\n    [] -> []\n    [\'\'] -> [\'\']\n    [\'\', \'\'] -> [\'_\']\n    [\'\', \'\', \'\', \'\'] -> [\'___\']\n    If reverse is true, empty strings are combined with closest non-empty string\n    on the right or "" if it is the last string.\n    """\n\n    def _rev(l):\n        return [s[::-1] for s in l][::-1]\n\n    if reverse:\n        return _rev(chomp_empty_strings(_rev(strings), c))\n    if not len(strings):\n        return strings\n    if sum(map(len, strings)) == 0:\n        return [c * (len(strings) - 1)]\n\n    class _Chomper:\n        def __init__(self, c):\n            self.c = c\n\n        def __call__(self, x, y):\n            # x is list up to now\n            # y is next item in list\n            # x should be [""] initially, and then empty strings filtered out at the\n            # end\n            if len(y) == 0:\n                return x[:-1] + [x[-1] + self.c]\n            else:\n                return x + [y]\n\n    return list(filter(len, reduce(_Chomper(c), strings, [""])))\n\n\n# taken from\n# https://en.wikibooks.org/wiki/Algorithm_Implementation/Strings/Levenshtein_distance#Python\ndef levenshtein(s1, s2):\n    if len(s1) < len(s2):\n        return levenshtein(s2, s1)  # len(s1) >= len(s2)\n    if len(s2) == 0:\n        return len(s1)\n    previous_row = range(len(s2) + 1)\n    for i, c1 in enumerate(s1):\n        current_row = [i + 1]\n        for j, c2 in enumerate(s2):\n            # j+1 instead of j since previous_row and current_row are one character longer\n            # than s2\n            insertions = previous_row[j + 1] + 1\n            deletions = current_row[j] + 1\n            substitutions = previous_row[j] + (c1 != c2)\n            current_row.append(min(insertions, deletions, substitutions))\n        previous_row = current_row\n    return previous_row[-1]\n\n\ndef find_closest_string(string, strings):\n    def _key(s):\n        # sort by levenshtein distance and lexographically to maintain a stable\n        # sort for different keys with the same levenshtein distance\n        return (levenshtein(s, string), s)\n\n    return sorted(strings, key=_key)[0]\n',
            'packages/python/plotly/plotly/tests/test_io/test_to_from_json.py': 'import plotly.graph_objs as go\nimport plotly.io as pio\nimport pytest\nimport plotly\nimport json\nimport os\nimport tempfile\nfrom unittest.mock import MagicMock\nfrom pathlib import Path\n\n\n# fixtures\n# --------\n@pytest.fixture\ndef fig1(request):\n    return go.Figure(\n        data=[\n            {"type": "scattergl", "marker": {"color": "green"}},\n            {\n                "type": "parcoords",\n                "dimensions": [{"values": [1, 2, 3]}, {"values": [3, 2, 1]}],\n                "line": {"color": "blue"},\n            },\n        ],\n        layout={"title": "Figure title"},\n    )\n\n\nopts = {\n    "separators": (",", ":"),\n    "cls": plotly.utils.PlotlyJSONEncoder,\n}\npretty_opts = {"indent": 2, "cls": plotly.utils.PlotlyJSONEncoder}\n\n\n# to_json\n# -------\ndef test_to_json(fig1):\n    assert pio.to_json(fig1, remove_uids=False) == json.dumps(fig1, **opts)\n\n\ndef test_to_json_remove_uids(fig1):\n    dict1 = fig1.to_dict()\n    for trace in dict1["data"]:\n        trace.pop("uid", None)\n\n    assert pio.to_json(fig1) == json.dumps(dict1, **opts)\n\n\ndef test_to_json_validate(fig1):\n    dict1 = fig1.to_dict()\n    dict1["layout"]["bogus"] = 37\n\n    with pytest.raises(ValueError):\n        pio.to_json(dict1)\n\n\ndef test_to_json_validate_false(fig1):\n    dict1 = fig1.to_dict()\n    dict1["layout"]["bogus"] = 37\n\n    assert pio.to_json(dict1, validate=False) == json.dumps(dict1, **opts)\n\n\ndef test_to_json_pretty_print(fig1):\n    assert pio.to_json(fig1, remove_uids=False, pretty=True) == json.dumps(\n        fig1, **pretty_opts\n    )\n\n\n# from_json\n# ---------\ndef test_from_json(fig1):\n    fig1_json = json.dumps(fig1, **opts)\n    fig1_loaded = pio.from_json(fig1_json)\n\n    # Check return type\n    assert isinstance(fig1_loaded, go.Figure)\n\n    # Check return json\n    assert pio.to_json(fig1_loaded) == pio.to_json(fig1.to_dict())\n\n\n@pytest.mark.parametrize(\n    "fig_type_spec,fig_type",\n    [\n        ("Figure", go.Figure),\n        (go.Figure, go.Figure),\n        ("FigureWidget", go.FigureWidget),\n        (go.FigureWidget, go.FigureWidget),\n    ],\n)\ndef test_from_json_output_type(fig1, fig_type_spec, fig_type):\n    fig1_json = json.dumps(fig1, **opts)\n    fig1_loaded = pio.from_json(fig1_json, output_type=fig_type_spec)\n\n    # Check return type\n    assert isinstance(fig1_loaded, fig_type)\n\n    # Check return json\n    assert pio.to_json(fig1_loaded) == pio.to_json(fig1.to_dict())\n\n\ndef test_from_json_invalid(fig1):\n    dict1 = fig1.to_dict()\n\n    # Set bad property name\n    dict1["data"][0]["marker"]["bogus"] = 123\n\n    # Set property with bad value\n    dict1["data"][0]["marker"]["size"] = -1\n\n    # Serialize to json\n    bad_json = json.dumps(dict1, **opts)\n\n    with pytest.raises(ValueError):\n        pio.from_json(bad_json)\n\n\ndef test_from_json_skip_invalid(fig1):\n    dict1 = fig1.to_dict()\n\n    # Set bad property name\n    dict1["data"][0]["marker"]["bogus"] = 123\n\n    # Set property with bad value\n    dict1["data"][0]["marker"]["size"] = -1\n\n    # Serialize to json\n    bad_json = json.dumps(dict1, **opts)\n    fig1_loaded = pio.from_json(bad_json, skip_invalid=True)\n\n    # Check loaded figure\n    assert pio.to_json(fig1_loaded) == pio.to_json(fig1.to_dict())\n\n\n# read_json\n# ---------\n@pytest.mark.parametrize(\n    "fig_type_spec,fig_type",\n    [\n        ("Figure", go.Figure),\n        (go.Figure, go.Figure),\n        ("FigureWidget", go.FigureWidget),\n        (go.FigureWidget, go.FigureWidget),\n    ],\n)\ndef test_read_json_from_filelike(fig1, fig_type_spec, fig_type):\n    # Configure file-like mock\n    filemock = MagicMock()\n    del filemock.read_text\n    filemock.read.return_value = pio.to_json(fig1)\n\n    # read_json on mock file\n    fig1_loaded = pio.read_json(filemock, output_type=fig_type_spec)\n\n    # Check return type\n    assert isinstance(fig1_loaded, fig_type)\n\n    # Check loaded figure\n    assert pio.to_json(fig1_loaded) == pio.to_json(fig1.to_dict())\n\n\n@pytest.mark.parametrize(\n    "fig_type_spec,fig_type",\n    [\n        ("Figure", go.Figure),\n        (go.Figure, go.Figure),\n        ("FigureWidget", go.FigureWidget),\n        (go.FigureWidget, go.FigureWidget),\n    ],\n)\ndef test_read_json_from_pathlib(fig1, fig_type_spec, fig_type):\n    # Configure pathlib.Path-like mock\n    filemock = MagicMock(spec=Path)\n    filemock.read_text.return_value = pio.to_json(fig1)\n\n    # read_json on mock file\n    fig1_loaded = pio.read_json(filemock, output_type=fig_type_spec)\n\n    # Check return type\n    assert isinstance(fig1_loaded, fig_type)\n\n    # Check loaded figure\n    assert pio.to_json(fig1_loaded) == pio.to_json(fig1.to_dict())\n\n\n@pytest.mark.parametrize(\n    "fig_type_spec,fig_type",\n    [\n        ("Figure", go.Figure),\n        (go.Figure, go.Figure),\n        ("FigureWidget", go.FigureWidget),\n        (go.FigureWidget, go.FigureWidget),\n    ],\n)\ndef test_read_json_from_file_string(fig1, fig_type_spec, fig_type):\n    with tempfile.TemporaryDirectory() as dir_name:\n\n        # Write json file\n        path = os.path.join(dir_name, "fig1.json")\n        with open(path, "w") as f:\n            f.write(pio.to_json(fig1))\n\n        # read json from file as string\n        fig1_loaded = pio.read_json(path, output_type=fig_type_spec)\n\n        # Check return type\n        assert isinstance(fig1_loaded, fig_type)\n\n        # Check loaded figure\n        assert pio.to_json(fig1_loaded) == pio.to_json(fig1.to_dict())\n\n\n# write_json\n# ----------\n@pytest.mark.parametrize("pretty", [True, False])\n@pytest.mark.parametrize("remove_uids", [True, False])\ndef test_write_json_filelike(fig1, pretty, remove_uids):\n    # Configure file-like mock\n    filemock = MagicMock()\n    del filemock.write_text\n\n    # write_json to mock file\n    pio.write_json(fig1, filemock, pretty=pretty, remove_uids=remove_uids)\n\n    # check write contents\n    expected = pio.to_json(fig1, pretty=pretty, remove_uids=remove_uids)\n    filemock.write.assert_called_once_with(expected)\n\n\n@pytest.mark.parametrize("pretty", [True, False])\n@pytest.mark.parametrize("remove_uids", [True, False])\ndef test_write_json_pathlib(fig1, pretty, remove_uids):\n    # Configure file-like mock\n    filemock = MagicMock(spec=Path)\n\n    # write_json to mock file\n    pio.write_json(fig1, filemock, pretty=pretty, remove_uids=remove_uids)\n\n    # check write contents\n    expected = pio.to_json(fig1, pretty=pretty, remove_uids=remove_uids)\n    filemock.write_text.assert_called_once_with(expected)\n\n\n@pytest.mark.parametrize("pretty", [True, False])\n@pytest.mark.parametrize("remove_uids", [True, False])\ndef test_write_json_from_file_string(fig1, pretty, remove_uids):\n    with tempfile.TemporaryDirectory() as dir_name:\n\n        # Write json\n        path = os.path.join(dir_name, "fig1.json")\n        pio.write_json(fig1, path, pretty=pretty, remove_uids=remove_uids)\n\n        # Open as text file\n        with open(path, "r") as f:\n            result = f.read()\n\n        # Check contents that were written\n        expected = pio.to_json(fig1, pretty=pretty, remove_uids=remove_uids)\n        assert result == expected\n',
            'packages/python/plotly/plotly/tests/test_optional/test_px/test_px.py': 'import plotly.express as px\nimport plotly.io as pio\nimport narwhals.stable.v1 as nw\nimport numpy as np\nimport pytest\nfrom itertools import permutations\n\n\ndef test_scatter(backend):\n    iris = nw.from_native(px.data.iris(return_type=backend))\n    fig = px.scatter(iris.to_native(), x="sepal_width", y="sepal_length")\n    assert fig.data[0].type == "scatter"\n    assert np.all(fig.data[0].x == iris.get_column("sepal_width").to_numpy())\n    assert np.all(fig.data[0].y == iris.get_column("sepal_length").to_numpy())\n    # test defaults\n    assert fig.data[0].mode == "markers"\n\n\ndef test_custom_data_scatter(backend):\n    iris = nw.from_native(px.data.iris(return_type=backend))\n    # No hover, no custom data\n    fig = px.scatter(\n        iris.to_native(), x="sepal_width", y="sepal_length", color="species"\n    )\n    assert fig.data[0].customdata is None\n    # Hover, no custom data\n    fig = px.scatter(\n        iris.to_native(),\n        x="sepal_width",\n        y="sepal_length",\n        color="species",\n        hover_data=["petal_length", "petal_width"],\n    )\n    for data in fig.data:\n        assert np.all(\n            np.in1d(data.customdata[:, 1], iris.get_column("petal_width").to_numpy())\n        )\n    # Hover and custom data, no repeated arguments\n    fig = px.scatter(\n        iris.to_native(),\n        x="sepal_width",\n        y="sepal_length",\n        hover_data=["petal_length", "petal_width"],\n        custom_data=["species_id", "species"],\n    )\n    assert np.all(\n        fig.data[0].customdata[:, 0] == iris.get_column("species_id").to_numpy()\n    )\n    assert fig.data[0].customdata.shape[1] == 4\n    # Hover and custom data, with repeated arguments\n    fig = px.scatter(\n        iris.to_native(),\n        x="sepal_width",\n        y="sepal_length",\n        hover_data=["petal_length", "petal_width", "species_id"],\n        custom_data=["species_id", "species"],\n    )\n    assert np.all(\n        fig.data[0].customdata[:, 0] == iris.get_column("species_id").to_numpy()\n    )\n    assert fig.data[0].customdata.shape[1] == 4\n    assert (\n        fig.data[0].hovertemplate\n        == "sepal_width=%{x}<br>sepal_length=%{y}<br>petal_length=%{customdata[2]}<br>petal_width=%{customdata[3]}<br>species_id=%{customdata[0]}<extra></extra>"\n    )\n\n\ndef test_labels(backend):\n    tips = nw.from_native(px.data.tips(return_type=backend))\n    fig = px.scatter(\n        tips.to_native(),\n        x="total_bill",\n        y="tip",\n        facet_row="time",\n        facet_col="day",\n        color="size",\n        symbol="sex",\n        labels={c: c.upper() for c in tips.columns},\n    )\n    assert "SEX" in fig.data[0].hovertemplate\n    assert "TOTAL_BILL" in fig.data[0].hovertemplate\n    assert "SIZE" in fig.data[0].hovertemplate\n    assert "DAY" in fig.data[0].hovertemplate\n    assert "TIME" in fig.data[0].hovertemplate\n    assert fig.layout.legend.title.text.startswith("SEX")\n    assert fig.layout.xaxis.title.text == "TOTAL_BILL"\n    assert fig.layout.coloraxis.colorbar.title.text == "SIZE"\n    assert fig.layout.annotations[0].text.startswith("DAY")\n    assert fig.layout.annotations[4].text.startswith("TIME")\n\n\n@pytest.mark.parametrize(\n    ["extra_kwargs", "expected_mode"],\n    [\n        ({}, "lines"),\n        ({"markers": True}, "lines+markers"),\n        ({"text": "continent"}, "lines+markers+text"),\n    ],\n)\ndef test_line_mode(backend, extra_kwargs, expected_mode):\n    gapminder = px.data.gapminder(return_type=backend)\n    fig = px.line(\n        gapminder,\n        x="year",\n        y="pop",\n        color="country",\n        **extra_kwargs,\n    )\n    assert fig.data[0].mode == expected_mode\n\n\ndef test_px_templates(backend):\n    try:\n        import plotly.graph_objects as go\n\n        tips = px.data.tips(return_type=backend)\n\n        # use the normal defaults\n        fig = px.scatter()\n        assert fig.layout.template == pio.templates[pio.templates.default]\n\n        # respect changes to defaults\n        pio.templates.default = "seaborn"\n        fig = px.scatter()\n        assert fig.layout.template == pio.templates["seaborn"]\n\n        # special px-level defaults over pio defaults\n        pio.templates.default = "seaborn"\n        px.defaults.template = "ggplot2"\n        fig = px.scatter()\n        assert fig.layout.template == pio.templates["ggplot2"]\n\n        # accept names in args over pio and px defaults\n        fig = px.scatter(template="seaborn")\n        assert fig.layout.template == pio.templates["seaborn"]\n\n        # accept objects in args\n        fig = px.scatter(template={})\n        assert fig.layout.template == go.layout.Template(data_scatter=[{}])\n\n        # read colorway from the template\n        fig = px.scatter(\n            tips,\n            x="total_bill",\n            y="tip",\n            color="sex",\n            template=dict(layout_colorway=["red", "blue"]),\n        )\n        assert fig.data[0].marker.color == "red"\n        assert fig.data[1].marker.color == "blue"\n\n        # default colorway fallback\n        fig = px.scatter(tips, x="total_bill", y="tip", color="sex", template=dict())\n        assert fig.data[0].marker.color == px.colors.qualitative.D3[0]\n        assert fig.data[1].marker.color == px.colors.qualitative.D3[1]\n\n        # pio default template colorway fallback\n        pio.templates.default = "seaborn"\n        px.defaults.template = None\n        fig = px.scatter(tips, x="total_bill", y="tip", color="sex")\n        assert fig.data[0].marker.color == pio.templates["seaborn"].layout.colorway[0]\n        assert fig.data[1].marker.color == pio.templates["seaborn"].layout.colorway[1]\n\n        # pio default template colorway fallback\n        pio.templates.default = "seaborn"\n        px.defaults.template = "ggplot2"\n        fig = px.scatter(tips, x="total_bill", y="tip", color="sex")\n        assert fig.data[0].marker.color == pio.templates["ggplot2"].layout.colorway[0]\n        assert fig.data[1].marker.color == pio.templates["ggplot2"].layout.colorway[1]\n\n        # don\'t overwrite top margin when set in template\n        fig = px.scatter(title="yo")\n        assert fig.layout.margin.t is None\n\n        fig = px.scatter()\n        assert fig.layout.margin.t == 60\n\n        fig = px.scatter(template=dict(layout_margin_t=2))\n        assert fig.layout.margin.t is None\n\n        # don\'t force histogram gridlines when set in template\n        pio.templates.default = "none"\n        px.defaults.template = None\n        fig = px.scatter(\n            tips,\n            x="total_bill",\n            y="tip",\n            marginal_x="histogram",\n            marginal_y="histogram",\n        )\n        assert fig.layout.xaxis2.showgrid\n        assert fig.layout.xaxis3.showgrid\n        assert fig.layout.yaxis2.showgrid\n        assert fig.layout.yaxis3.showgrid\n\n        fig = px.scatter(\n            tips,\n            x="total_bill",\n            y="tip",\n            marginal_x="histogram",\n            marginal_y="histogram",\n            template=dict(layout_yaxis_showgrid=False),\n        )\n        assert fig.layout.xaxis2.showgrid\n        assert fig.layout.xaxis3.showgrid\n        assert fig.layout.yaxis2.showgrid is None\n        assert fig.layout.yaxis3.showgrid is None\n\n        fig = px.scatter(\n            tips,\n            x="total_bill",\n            y="tip",\n            marginal_x="histogram",\n            marginal_y="histogram",\n            template=dict(layout_xaxis_showgrid=False),\n        )\n        assert fig.layout.xaxis2.showgrid is None\n        assert fig.layout.xaxis3.showgrid is None\n        assert fig.layout.yaxis2.showgrid\n        assert fig.layout.yaxis3.showgrid\n    finally:\n        # reset defaults to prevent all other tests from failing if this one does\n        px.defaults.reset()\n        pio.templates.default = "plotly"\n\n\ndef test_px_defaults():\n    px.defaults.labels = dict(x="hey x")\n    px.defaults.category_orders = dict(color=["b", "a"])\n    px.defaults.color_discrete_map = dict(b="red")\n    fig = px.scatter(x=[1, 2], y=[1, 2], color=["a", "b"])\n    try:\n        assert fig.data[0].name == "b"\n        assert fig.data[0].marker.color == "red"\n        assert fig.layout.xaxis.title.text == "hey x"\n    finally:\n        # reset defaults to prevent all other tests from failing if this one does\n        px.defaults.reset()\n        pio.templates.default = "plotly"\n\n\ndef assert_orderings(backend, days_order, days_check, times_order, times_check):\n    symbol_sequence = ["circle", "diamond", "square", "cross", "circle", "diamond"]\n    color_sequence = ["red", "blue", "red", "blue", "red", "blue", "red", "blue"]\n\n    tips = nw.from_native(px.data.tips(return_type=backend))\n\n    fig = px.scatter(\n        tips.to_native(),\n        x="total_bill",\n        y="tip",\n        facet_row="time",\n        facet_col="day",\n        color="time",\n        symbol="day",\n        symbol_sequence=symbol_sequence,\n        color_discrete_sequence=color_sequence,\n        category_orders=dict(day=days_order, time=times_order),\n    )\n\n    for col in range(len(days_check)):\n        for trace in fig.select_traces(col=col + 1):\n            assert days_check[col] in trace.hovertemplate\n\n    for row in range(len(times_check)):\n        for trace in fig.select_traces(row=len(times_check) - row):\n            assert times_check[row] in trace.hovertemplate\n\n    for trace in fig.data:\n        for i, day in enumerate(days_check):\n            if day in trace.name:\n                assert trace.marker.symbol == symbol_sequence[i]\n        for i, time in enumerate(times_check):\n            if time in trace.name:\n                assert trace.marker.color == color_sequence[i]\n\n\n@pytest.mark.parametrize("days", permutations(["Sun", "Sat", "Fri", "x"]))\n@pytest.mark.parametrize("times", permutations(["Lunch", "x"]))\ndef test_orthogonal_and_missing_orderings(backend, days, times):\n    assert_orderings(\n        backend, days, list(days) + ["Thur"], times, list(times) + ["Dinner"]\n    )\n\n\n@pytest.mark.parametrize("days", permutations(["Sun", "Sat", "Fri", "Thur"]))\n@pytest.mark.parametrize("times", permutations(["Lunch", "Dinner"]))\ndef test_orthogonal_orderings(backend, days, times):\n    assert_orderings(backend, days, days, times, times)\n\n\ndef test_category_order_with_category_as_x(backend):\n    # https://github.com/plotly/plotly.py/issues/4875\n    tips = nw.from_native(px.data.tips(return_type=backend))\n    fig = px.bar(\n        tips.to_native(),\n        x="day",\n        y="total_bill",\n        color="smoker",\n        barmode="group",\n        facet_col="sex",\n        category_orders={\n            "day": ["Thur", "Fri", "Sat", "Sun"],\n            "smoker": ["Yes", "No"],\n            "sex": ["Male", "Female"],\n        },\n    )\n    assert fig["layout"]["xaxis"]["categoryarray"] == ("Thur", "Fri", "Sat", "Sun")\n    for trace in fig["data"]:\n        assert set(trace["x"]) == {"Thur", "Fri", "Sat", "Sun"}\n\n\ndef test_permissive_defaults():\n    msg = "\'PxDefaults\' object has no attribute \'should_not_work\'"\n    with pytest.raises(AttributeError, match=msg):\n        px.defaults.should_not_work = "test"\n\n\ndef test_marginal_ranges(backend):\n    df = px.data.tips(return_type=backend)\n    fig = px.scatter(\n        df,\n        x="total_bill",\n        y="tip",\n        marginal_x="histogram",\n        marginal_y="histogram",\n        range_x=[5, 10],\n        range_y=[5, 10],\n    )\n    assert fig.layout.xaxis2.range is None\n    assert fig.layout.yaxis3.range is None\n\n\ndef test_render_mode(backend):\n    df = nw.from_native(px.data.gapminder(return_type=backend))\n    df2007 = df.filter(nw.col("year") == 2007)\n\n    fig = px.scatter(df2007.to_native(), x="gdpPercap", y="lifeExp", trendline="ols")\n    assert fig.data[0].type == "scatter"\n    assert fig.data[1].type == "scatter"\n    fig = px.scatter(\n        df2007.to_native(),\n        x="gdpPercap",\n        y="lifeExp",\n        trendline="ols",\n        render_mode="webgl",\n    )\n    assert fig.data[0].type == "scattergl"\n    assert fig.data[1].type == "scattergl"\n    fig = px.scatter(df.to_native(), x="gdpPercap", y="lifeExp", trendline="ols")\n    assert fig.data[0].type == "scattergl"\n    assert fig.data[1].type == "scattergl"\n    fig = px.scatter(\n        df.to_native(), x="gdpPercap", y="lifeExp", trendline="ols", render_mode="svg"\n    )\n    assert fig.data[0].type == "scatter"\n    assert fig.data[1].type == "scatter"\n    fig = px.density_contour(\n        df.to_native(), x="gdpPercap", y="lifeExp", trendline="ols"\n    )\n    assert fig.data[0].type == "histogram2dcontour"\n    assert fig.data[1].type == "scatter"\n',
        }
